/**
 * API Client for Todo AI Chatbot Backend
 */

const API_BASE_URL = process.env.NEXT_PUBLIC_API_BASE_URL || 'http://localhost:8000';

export interface Message {
  id: string;
  conversation_id: string;
  role: 'user' | 'assistant' | 'system';
  content: string;
  created_at: string;
}

export interface ToolCall {
  tool: string;
  result: Record<string, any>;
}

export interface ChatResponse {
  conversation_id: string;
  message: Message;
  tool_calls: ToolCall[];
}

export interface Conversation {
  id: string;
  user_id: string;
  session_id: string;
  created_at: string;
  updated_at: string;
}

/**
 * Get JWT token from Better Auth session
 */
async function getToken(): Promise<string | null> {
  // Better Auth stores session token in cookies and localStorage
  // Try multiple possible storage locations
  const token = localStorage.getItem('better-auth-session_token');
  
  if (!token) {
    // Try alternative storage locations
    const authData = localStorage.getItem('better-auth_data');
    if (authData) {
      try {
        const data = JSON.parse(authData);
        return data.token || null;
      } catch {
        return null;
      }
    }
  }
  
  return token;
}

/**
 * Send a message to the AI chatbot
 */
export async function sendMessage(
  message: string,
  conversationId?: string
): Promise<ChatResponse> {
  const token = await getToken();
  
  if (!token) {
    throw new Error('Not authenticated. Please log in first.');
  }

  const response = await fetch(`${API_BASE_URL}/api/chat/`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${token}`,
    },
    body: JSON.stringify({
      message,
      conversation_id: conversationId,
    }),
  });

  if (!response.ok) {
    const error = await response.json();
    throw new Error(error.detail || 'Failed to send message');
  }

  return response.json();
}

